@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _element, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already gone — nothing to clean up on the JS side.
            }
        }
        _dotNetRef?.Dispose();
    }
}

let state = null;

export function initialize(element, dotNetRef, timeoutMs) {
    const handler = () => {
        if (state.isIdle) {
            state.isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }
        clearTimeout(state.timerId);
        state.timerId = setTimeout(() => {
            state.isIdle = true;
            dotNetRef.invokeMethodAsync("OnIdleCallback");
        }, timeoutMs);
    };

    const events = ["mousemove", "keydown", "click", "scroll"];
    events.forEach(e => element.addEventListener(e, handler, { passive: true }));

    const timerId = setTimeout(() => {
        state.isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);

    state = { element, handler, events, timerId, isIdle: false };
}

export function dispose() {
    if (!state) return;
    clearTimeout(state.timerId);
    state.events.forEach(e => state.element.removeEventListener(e, state.handler));
    state = null;
}

